+// ============================================================================
+// Optimization 4: ArenaAllocator for Short-Term Memory
+// ============================================================================
+
+/// Arena-based allocator for efficient conversation memory management.
+/// When the system goes to "Sleep" and consolidates memory into weights,
+/// the entire arena can be freed in one CPU instruction instead of
+/// walking a linked list of thousands of event objects.
+pub const ConversationArena = struct {
+    arena: std.heap.ArenaAllocator,
+    entry_count: usize,
+
+    pub fn init(backing_allocator: std.mem.Allocator) ConversationArena {
+        return .{
+            .arena = std.heap.ArenaAllocator.init(backing_allocator),
+            .entry_count = 0,
+        };
+    }
+
+    /// Get the arena allocator for allocating conversation data
+    pub fn allocator(self: *ConversationArena) std.mem.Allocator {
+        return self.arena.allocator();
+    }
+
+    /// Free all conversation memory in one operation (O(1) instead of O(n))
+    /// Called when memories are consolidated into LoRA weights
+    pub fn consolidateAndReset(self: *ConversationArena) void {
+        // Single operation frees all memory - no iteration needed
+        self.arena.deinit();
+        self.arena = std.heap.ArenaAllocator.init(self.arena.child_allocator);
+        self.entry_count = 0;
+    }
+
+    /// Track entry count for statistics
+    pub fn incrementEntryCount(self: *ConversationArena) void {
+        self.entry_count += 1;
+    }
+
+    pub fn getEntryCount(self: *const ConversationArena) usize {
+        return self.entry_count;
+    }
+
+    pub fn deinit(self: *ConversationArena) void {
+        self.arena.deinit();
+    }
+};
