     /// Interrupt the sleep cycle (wake up immediately)
     pub fn interrupt(self: *Hippocampus) !void {
         const current = self.state.load(.monotonic);
-        if (current == .drowsy or current == .dreaming) {
+        if (current == .drowsy or current == .dreaming or current == .pre_drowsy) {
             logger.info("Hippocampus: Waking up (interrupted)", .{});
             self.state.store(.awake, .monotonic);
             // Thread will detect state change and exit gracefully
         }
     }
+
+    // =========================================================================
+    // Optimization 1: "Lucid Dreaming" - Speculative Pre-computation
+    // =========================================================================
+
+    /// Record user activity (resets the pre-drowsy timer)
+    pub fn recordActivity(self: *Hippocampus) void {
+        self.last_activity_time = std.time.milliTimestamp();
+
+        // If we were in pre_drowsy, discard precomputed gradients (cheap)
+        const current = self.state.load(.monotonic);
+        if (current == .pre_drowsy) {
+            logger.debug("User activity detected, discarding pre-computed gradients", .{});
+            self.state.store(.awake, .monotonic);
+            // Gradients will be cleaned up when thread exits
+        }
+    }
+
+    /// Check if we should enter pre-drowsy state (30 seconds idle)
+    pub fn checkPreDrowsy(self: *Hippocampus) !void {
+        const current = self.state.load(.monotonic);
+        if (current != .awake) return;
+
+        const now = std.time.milliTimestamp();
+        const idle_time = now - self.last_activity_time;
+
+        if (idle_time >= self.pre_drowsy_threshold_ms) {
+            // Check if there are events worth pre-computing
+            const latest_event = try self.conversation_logger.getLatestEventId();
+            if (latest_event <= self.last_consolidated_event_id) return;
+
+            const new_events = latest_event - self.last_consolidated_event_id;
+            if (new_events < 3) return; // Need at least 3 events
+
+            logger.info("Hippocampus: Entering pre-drowsy (light sleep) after {d}ms idle", .{idle_time});
+            self.state.store(.pre_drowsy, .monotonic);
+
+            // Spawn pre-computation thread
+            self.pre_drowsy_thread = try std.Thread.spawn(.{}, preDrowsyEntryPoint, .{self});
+        }
+    }
+
+    /// Pre-drowsy thread: speculatively prepare training data
+    fn preDrowsyEntryPoint(self: *Hippocampus) void {
+        defer {
+            self.pre_drowsy_thread = null;
+        }
+
+        // Check if still in pre_drowsy state
+        if (self.state.load(.monotonic) != .pre_drowsy) {
+            logger.debug("Pre-drowsy cancelled before preparation", .{});
+            return;
+        }
+
+        // Prepare training data (80% of the work)
+        const gradients = self.prepareGradients() catch |err| {
+            logger.warn("Pre-drowsy gradient preparation failed: {}", .{err});
+            self.state.store(.awake, .monotonic);
+            return;
+        };
+
+        // Store precomputed gradients
+        if (self.precomputed_gradients) |*old| {
+            old.deinit(self.allocator);
+        }
+        self.precomputed_gradients = gradients;
+
+        logger.info("Pre-drowsy: Gradients pre-computed, ready for fast training", .{});
+
+        // Stay in pre_drowsy until either:
+        // 1. User activity (recordActivity called) -> discard
+        // 2. Full sleep threshold reached (trySleep called) -> use precomputed
+    }
+
+    /// Prepare gradients speculatively (used in pre-drowsy)
+    fn prepareGradients(self: *Hippocampus) !PrecomputedGradients {
+        // Fetch unconsolidated events
+        const new_events = try self.conversation_logger.fetchUnconsolidated(1000);
+        errdefer {
+            for (new_events) |*e| e.deinit(self.allocator);
+            self.allocator.free(new_events);
+        }
+
+        if (new_events.len == 0) return error.NoEvents;
+
+        // Fetch replay buffer
+        const replay_count = @max(1, @as(usize, @intFromFloat(
+            @as(f32, @floatFromInt(new_events.len)) * self.replay_buffer_ratio,
+        )));
+        const replay_events = try self.conversation_logger.sampleConsolidated(replay_count);
+        defer {
+            for (replay_events) |*e| e.deinit(self.allocator);
+            self.allocator.free(replay_events);
+        }
+
+        // Format training data
+        const training_examples = try self.formatTrainingData(new_events, replay_events);
+
+        // Store event IDs for marking consolidated later
+        var event_ids = try self.allocator.alloc(u64, new_events.len);
+        for (new_events, 0..) |e, i| {
+            event_ids[i] = e.event_id;
+        }
+
+        // Clean up new_events (we've extracted what we need)
+        for (new_events) |*e| e.deinit(self.allocator);
+        self.allocator.free(new_events);
+
+        return PrecomputedGradients{
+            .training_examples = training_examples,
+            .event_ids = event_ids,
+            .computed_at = std.time.milliTimestamp(),
+        };
+    }
+
+    // =========================================================================
+    // Optimization 2: Dual-Adapter Ping-Pong Buffering
+    // =========================================================================
+
+    /// Get the currently active adapter path for inference
+    pub fn getActiveAdapterPath(self: *const Hippocampus) ?[]const u8 {
+        return self.dual_adapter.active_path;
+    }
+
+    /// Initialize dual adapter paths
+    pub fn initDualAdapters(self: *Hippocampus) !void {
+        const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+        // Adapter A (slot 0)
+        const path_a = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/.cache/zell/lora/{s}_A.lora",
+            .{ home, self.adapter_name },
+        );
+
+        // Adapter B (slot 1)
+        const path_b = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/.cache/zell/lora/{s}_B.lora",
+            .{ home, self.adapter_name },
+        );
+
+        // Ensure directory exists
+        const dir_path = std.fs.path.dirname(path_a) orelse return;
+        try std.fs.cwd().makePath(dir_path);
+
+        // Check which adapter exists and is valid
+        const a_exists = std.fs.cwd().access(path_a, .{}) != error.FileNotFound;
+        const b_exists = std.fs.cwd().access(path_b, .{}) != error.FileNotFound;
+
+        if (a_exists) {
+            self.dual_adapter.active_path = path_a;
+            self.dual_adapter.training_path = path_b;
+            self.dual_adapter.active_slot = 0;
+        } else if (b_exists) {
+            self.dual_adapter.active_path = path_b;
+            self.dual_adapter.training_path = path_a;
+            self.dual_adapter.active_slot = 1;
+        } else {
+            // Neither exists, set up for first training
+            self.dual_adapter.active_path = null;
+            self.dual_adapter.training_path = path_a;
+            self.allocator.free(path_b);
+        }
+    }
+
+    /// Swap adapters after training completes (zero-latency)
+    fn swapAdapters(self: *Hippocampus) void {
+        self.dual_adapter.swap();
+        logger.info("Dual-adapter swap: Now using slot {d}", .{self.dual_adapter.active_slot});
+    }
+
+    // =========================================================================
+    // Optimization 3: KV Cache Partial Invalidation
+    // =========================================================================
+
+    /// Track which concepts were affected during training
+    fn trackAffectedConcepts(self: *Hippocampus, training_examples: []const TrainingExample) !void {
+        self.affected_concepts.clearRetainingCapacity();
+
+        for (training_examples) |example| {
+            // Simple concept extraction: hash words/phrases
+            var words = std.mem.tokenizeAny(u8, example.text, " \n\t.,;:!?");
+            while (words.next()) |word| {
+                if (word.len < 3) continue; // Skip short words
+                const concept_hash = std.hash.Wyhash.hash(0, word);
+                const current = self.affected_concepts.get(concept_hash) orelse 0.0;
+                try self.affected_concepts.put(concept_hash, current + 1.0);
+            }
+        }
+
+        logger.debug("Tracked {d} affected concepts", .{self.affected_concepts.count()});
+    }
+
+    /// Check if a concept was affected by training (for partial invalidation)
+    pub fn isConceptAffected(self: *const Hippocampus, text: []const u8) bool {
+        const concept_hash = std.hash.Wyhash.hash(0, text);
+        return self.affected_concepts.contains(concept_hash);
+    }
+
+    /// Invalidate KV caches selectively (only non-system-prompt regions)
+    fn invalidateKVCacheSelective(self: *Hippocampus) !void {
+        const home = std.posix.getenv("HOME") orelse return;
+        const cache_dir = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/.cache/zell/",
+            .{home},
+        );
+        defer self.allocator.free(cache_dir);
+
+        var dir = std.fs.cwd().openDir(cache_dir, .{ .iterate = true }) catch return;
+        defer dir.close();
+
+        var iter = dir.iterate();
+        while (try iter.next()) |entry| {
+            // Skip system prompt caches if pinned
+            if (self.system_prompt_pinned and std.mem.startsWith(u8, entry.name, "system_prompt_")) {
+                logger.debug("Skipping pinned system prompt cache: {s}", .{entry.name});
+                continue;
+            }
+
+            // Only mark conversation caches as stale
+            if (!std.mem.endsWith(u8, entry.name, ".bin")) continue;
+
+            const new_name = try std.fmt.allocPrint(
+                self.allocator,
+                "{s}.stale",
+                .{entry.name},
+            );
+            defer self.allocator.free(new_name);
+
+            dir.rename(entry.name, new_name) catch |err| {
+                logger.warn("Failed to mark cache stale: {}", .{err});
+            };
+        }
+
+        logger.info("KV caches selectively invalidated (system prompt preserved)", .{});
+    }
 };

